import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { navigateStudio, pollAgentSessionEvents, pushAgentSessionEvent, } from "./agentSessionChannel.js";
const SERVICE_URL = "https://test.invalid";
const API_KEY = "key-test";
const SESSION_ID = "11111111-1111-4111-8111-111111111111";
function makeNavigateEvent(id, path) {
    return { id, type: "agent:navigate", data: { path } };
}
function jsonResponse(body, init) {
    return new Response(JSON.stringify(body), {
        status: 200,
        headers: { "Content-Type": "application/json" },
        ...init,
    });
}
describe("pushAgentSessionEvent", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("POSTs to /api/plugin/events with bearer auth and the session payload", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ id: "1735689600000-0" }));
        const result = await pushAgentSessionEvent({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, { type: "agent:navigate", data: { path: "/traces/abc" } });
        expect(result).toEqual({ id: "1735689600000-0" });
        const [calledUrl, init] = fetchMock.mock.calls[0];
        expect(calledUrl).toBe(`${SERVICE_URL}/api/plugin/events`);
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
        expect(JSON.parse(init.body)).toEqual({
            session: SESSION_ID,
            type: "agent:navigate",
            data: { path: "/traces/abc" },
        });
    });
    it("throws on non-2xx", async () => {
        fetchMock.mockResolvedValueOnce(new Response("forbidden", { status: 403 }));
        await expect(pushAgentSessionEvent({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, { type: "agent:navigate", data: { path: "/x" } })).rejects.toThrow(/403/);
    });
});
describe("navigateStudio", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("pushes an agent:navigate event with the given path", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ id: "1735689600000-0" }));
        const result = await navigateStudio({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, "/studio/experiments");
        expect(result).toEqual({ id: "1735689600000-0" });
        const [, init] = fetchMock.mock.calls[0];
        expect(JSON.parse(init.body)).toEqual({
            session: SESSION_ID,
            type: "agent:navigate",
            data: { path: "/studio/experiments" },
        });
    });
});
describe("pollAgentSessionEvents", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    it("emits events and advances the cursor across polls", async () => {
        const e1 = makeNavigateEvent("1735689600000-0", "/a");
        const e2 = makeNavigateEvent("1735689600001-0", "/b");
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [e1, e2] }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const events = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 100,
            abortSignal: abort.signal,
            onEvent: (event) => events.push(event),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(100);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(events).toEqual([e1, e2]);
        expect(fetchMock).toHaveBeenCalledTimes(2);
        const firstUrl = fetchMock.mock.calls[0][0];
        const secondUrl = fetchMock.mock.calls[1][0];
        expect(firstUrl).toContain(`session=${SESSION_ID}`);
        expect(firstUrl).not.toContain("since=");
        expect(secondUrl).toContain(`since=${encodeURIComponent(e2.id)}`);
    });
    it("respects startCursor on the first fetch", async () => {
        const start = "1735689600000-0";
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            startCursor: start,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const firstUrl = fetchMock.mock.calls[0][0];
        expect(firstUrl).toContain(`since=${encodeURIComponent(start)}`);
    });
    it("calls onError on non-2xx responses but keeps looping", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ error: "boom" }, { status: 500 }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const errors = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onError: (err) => errors.push(err),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(errors).toHaveLength(1);
        expect(errors[0].message).toMatch(/500/);
        expect(fetchMock).toHaveBeenCalledTimes(2);
    });
    it("terminates immediately when abort fires before the first fetch", async () => {
        const abort = new AbortController();
        abort.abort();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await loop;
        expect(fetchMock).not.toHaveBeenCalled();
    });
    it("sends the API key as a Bearer Authorization header", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const init = fetchMock.mock.calls[0][1];
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
    });
});
